SELECT [Sales Line].[Document Type], [Sales Line].Type, [Sales Header].No_ AS OrderNo, [Sales Line].[Line No_], [Sales Line].[Model Item No_], [Sales Line].No_, [Sales Line].[Unit of Measure], [Sales Line].[Variable Code 01], [Sales Line].[Variable Code 02], Salesperson_Purchaser.Name AS Salesperson, [Sales Line].[Delete Reason], [Sales Line].[Customer Price Group], [Sales Line].[Average Unit Price], [Sales Header].[Salesperson Code], [Sales Line].[Av_ Net Unit Price], Val([sales line.Average Unit Price]) AS GrossUnitPrice, Val([sales line.average unit price])*Val([sales line.no_ of pairs]) AS GrossSalesValue, [GrossSalesValue]-[ValueSold] AS DiscountValue, Val(nz([sales line.Area Manager Commission _]))*[valuesold]/100 AS AreaManagerCommissionValue, Val(nz([Sales Line.Salesperson Commission _]))*[valuesold]/100 AS SalesPersonCommissionValue, [Variable Code].[Order Variable Code], IIf(IsNull([Sales Line_1.Assortment Code]) Or [Sales Line_1.Assortment Code]="","XXX",[Sales Line_1.Assortment Code]) AS AssortmentCode, Val([sales line.Quantity]) AS QuantitySold, [Sales Line].[Currency Code], Val([sales line.No_ of pairs]) AS PairsSold, Val([sales line.Line Amount])-Val([sales line.Inv_ Discount Amount]) AS ValueSold, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity shipped])/Val([Sales Line.quantity])*(Val([sales line.Line Amount])-Val([sales line.Inv_ Discount Amount])),0) AS ValueShipped, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity shipped])/Val([Sales Line.quantity])*Val([Sales Line.no_ of pairs]),0) AS PairsShipped, Val([Sales Line.Quantity Shipped]) AS QuantityShipped, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity invoiced])/Val([Sales Line.quantity])*(Val([sales line.Line Amount])-Val([sales line.Inv_ Discount Amount])),0) AS ValueInvoiced, IIf(Val([Sales Line.quantity])>0,Val([Sales Line.quantity invoiced])/Val([Sales Line.quantity])*Val([Sales Line.no_ of pairs]),0) AS PairsInvoiced, Val([Sales Line.Quantity Invoiced]) AS QuantityInvoiced
FROM ((([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document No_] = [Sales Header].No_) AND ([Sales Line].[Document Type] = [Sales Header].[Document Type])) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) INNER JOIN [Variable Code] ON ([Sales Line].[Variable Code 02] = [Variable Code].[Variable Code]) AND ([Sales Line].[Variable Group 02] = [Variable Code].[Variable Group])) INNER JOIN [Sales Line] AS [Sales Line_1] ON ([Sales Line].[Document No_] = [Sales Line_1].[Document No_]) AND ([Sales Line].[Original Line No_] = [Sales Line_1].[Line No_])
WHERE ((([Sales Line].[Document Type])=1) AND (([Sales Line].Type)=2) AND (([Sales Line].[Delete Reason])=""))
ORDER BY [Sales Header].No_;

